import{_ as t,c as a,o as s,a5 as n}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse('{"title":"Changelog v3.14.0 (2026-05-09)","description":"NpgsqlRest v3.14.0: This release sharpens the philosophy of the standalone client: REST endpoints come from PostgreSQL routines (functions, procedures) and…","frontmatter":{"description":"NpgsqlRest v3.14.0: This release sharpens the philosophy of the standalone client: REST endpoints come from PostgreSQL routines (functions, procedures) and…","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/guide/changelog/v3.14.0.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/guide/changelog/v3.14.0.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Changelog v3.14.0 (2026-05-09)"}],["meta",{"property":"og:description","content":"NpgsqlRest v3.14.0: This release sharpens the philosophy of the standalone client: REST endpoints come from PostgreSQL routines (functions, procedures) and…"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Changelog v3.14.0 (2026-05-09)"}],["meta",{"name":"twitter:description","content":"NpgsqlRest v3.14.0: This release sharpens the philosophy of the standalone client: REST endpoints come from PostgreSQL routines (functions, procedures) and…"}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"guide/changelog/v3.14.0.md","filePath":"guide/changelog/v3.14.0.md","lastUpdated":1782480183000}'),o={name:"guide/changelog/v3.14.0.md"};function r(i,e,l,d,c,p){return s(),a("div",null,e[0]||(e[0]=[n(`<h1 id="changelog-v3-14-0-2026-05-09" tabindex="-1">Changelog v3.14.0 (2026-05-09) <a class="header-anchor" href="#changelog-v3-14-0-2026-05-09" aria-label="Permalink to &quot;Changelog v3.14.0 (2026-05-09)&quot;">​</a></h1><h2 id="version-3-14-0-2026-05-09" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.14.0" target="_blank" rel="noreferrer">3.14.0</a> (2026-05-09) <a class="header-anchor" href="#version-3-14-0-2026-05-09" aria-label="Permalink to &quot;Version [3.14.0](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.14.0) (2026-05-09)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.13.0...3.14.0" target="_blank" rel="noreferrer">Full Changelog</a></p><p>This release sharpens the philosophy of the standalone client: REST endpoints come from PostgreSQL routines (functions, procedures) and from explicit SQL files — not auto-generated CRUD on tables and views. It also makes real-time push (SSE) more honest about what your annotations mean, and gets more throughput out of array- and composite-heavy responses.</p><h2 id="removed-auto-crud-endpoint-generation-from-the-standalone-client" tabindex="-1">Removed: auto-CRUD endpoint generation from the standalone client <a class="header-anchor" href="#removed-auto-crud-endpoint-generation-from-the-standalone-client" aria-label="Permalink to &quot;Removed: auto-CRUD endpoint generation from the standalone client&quot;">​</a></h2><p>The <code>NpgsqlRest.CrudSource</code> plugin is <strong>no longer wired into the <code>NpgsqlRestClient</code> standalone executable</strong>. The plugin itself still ships as a NuGet package and remains fully functional for embedded use — projects that consume the <code>NpgsqlRest</code> library directly can continue to register a <code>CrudSource</code> instance against <code>EndpointSources</code> exactly as before. Only the <code>NpgsqlRestClient</code> JSON-driven path is affected.</p><p>Why: auto-generated CRUD endpoints over arbitrary tables and views have always been a different shape from the rest of the project. The core promise is &quot;your PostgreSQL routines become REST endpoints&quot; — explicit, version-controlled, comment-annotated procedures and functions where the developer chose what to expose. Auto-CRUD inverts that: every table becomes ten URL patterns by default (select / insert / update / delete plus the various <code>on conflict</code> and <code>returning</code> variants), with no per-endpoint guardrails unless you opt back into them. That&#39;s a different product, and it doesn&#39;t belong in the same configuration surface.</p><p>What this means in practice:</p><ul><li><strong><code>appsettings.json</code></strong>: the entire <code>NpgsqlRest:CrudSource</code> block has been removed from the default template. Any existing configuration with that block will fail key validation at startup (the same <code>Config:ValidateConfigKeys</code> check that catches typos) — remove the block to upgrade.</li><li><strong><code>--config</code> output</strong>: <code>CrudSource</code> no longer appears in the dumped configuration.</li><li><strong><code>--version</code> output</strong>: <code>NpgsqlRest.CrudSource</code> is no longer listed in either the human-readable or <code>--json</code> form, since the standalone client no longer references the assembly.</li><li><strong>Library use</strong>: zero change. <code>using NpgsqlRest.CrudSource; sources.Add(new CrudSource())</code> works exactly as it did in 3.13.0 and remains supported.</li></ul><p>If you had <code>&quot;CrudSource&quot;: { &quot;Enabled&quot;: true }</code> in your config and depend on the generated endpoints, the migration is one of:</p><ol><li>Switch to function-based wrappers — the recommended path. Write the CRUD shape you actually need as PostgreSQL functions or procedures with <code>HTTP</code> annotations. You get the same endpoints with explicit per-endpoint auth, validation, caching, rate limiting, and comment-driven URL shapes.</li><li>Embed the library in a custom host and register <code>CrudSource</code> programmatically. The plugin code still ships under <code>plugins/NpgsqlRest.CrudSource/</code>.</li></ol><h2 id="what-s-new" tabindex="-1">What&#39;s new <a class="header-anchor" href="#what-s-new" aria-label="Permalink to &quot;What&#39;s new&quot;">​</a></h2><h3 id="two-new-sse-annotations-sse-publish-and-sse-subscribe" tabindex="-1">Two new SSE annotations: <code>@sse_publish</code> and <code>@sse_subscribe</code> <a class="header-anchor" href="#two-new-sse-annotations-sse-publish-and-sse-subscribe" aria-label="Permalink to &quot;Two new SSE annotations: \`@sse_publish\` and \`@sse_subscribe\`&quot;">​</a></h3><p>If you&#39;ve ever had a manager-side procedure broadcast notifications to user-side subscribers, you&#39;ve probably hit the awkwardness of the all-in-one <code>@sse</code> annotation: every emitter procedure ended up with a phantom <code>/info</code> URL nobody connected to, and your generated TypeScript client included <code>createXEventSource()</code> helpers for procedures that should never be subscribed to.</p><p>3.14.0 splits the responsibilities:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Annotation</th><th>What it does</th></tr></thead><tbody><tr><td><code>@sse_publish</code></td><td>This procedure&#39;s <code>RAISE</code> statements feed SSE subscribers. No subscribe URL is exposed.</td></tr><tr><td><code>@sse_subscribe</code></td><td>Exposes a subscribe URL for <code>EventSource</code> clients. The procedure body is never executed when a client opens the stream.</td></tr><tr><td><code>@sse [path]</code></td><td>Same as before — shorthand for both. Unchanged.</td></tr></tbody></table></div></div><p>So a &quot;manager broadcasts to users&quot; flow now reads cleanly:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- subscriber URL, body never runs on subscribe</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function subscribe_user_events() is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@sse_subscribe</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- emitter, no subscribe URL, no useless TS EventSource helper</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">comment </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">on</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> procedure</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> broadcast_user_message(...) </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">is</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP POST</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@sse_publish</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@sse_scope authorize</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div></details><p>The TypeScript client generator follows automatically: <code>@sse_publish</code> produces a plain POST function, <code>@sse_subscribe</code> keeps the <code>EventSource</code> helper, and <code>@sse</code> is unchanged.</p><p>All existing event filtering — <code>@sse_scope</code>, <code>@sse_events_level</code>, <code>RAISE ... USING HINT</code>, and the <code>X-NpgsqlRest-ID</code> execution-id header — works the same with both new annotations.</p><h3 id="warning-when-a-raise-looks-like-a-missed-sse-publish" tabindex="-1">Warning when a <code>RAISE</code> looks like a missed <code>@sse_publish</code> <a class="header-anchor" href="#warning-when-a-raise-looks-like-a-missed-sse-publish" aria-label="Permalink to &quot;Warning when a \`RAISE\` looks like a missed \`@sse_publish\`&quot;">​</a></h3><p>Forgetting <code>@sse_publish</code> on an emitter procedure used to fail silently: the <code>RAISE</code> ran, the notice logged, and zero events reached subscribers. NpgsqlRest now warns once per endpoint when a <code>RAISE</code> whose severity matches the configured SSE forwarding level fires in a procedure that has no <code>@sse</code> or <code>@sse_publish</code>:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>WARN: RAISE INFO in endpoint /api/update-user-roles was not broadcast to SSE subscribers —</span></span>
<span class="line"><span>the endpoint has no @sse or @sse_publish annotation. Add @sse_publish to forward this</span></span>
<span class="line"><span>routine&#39;s notices, or set WarnUnboundServerSentEventsNotices=false to silence this warning.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p>The warning only fires when the project actually uses SSE somewhere and only when the severity matches — projects that use <code>RAISE NOTICE</code> for unrelated logging see no warnings, and projects that don&#39;t use SSE at all see no warnings. Configurable via the new <code>WarnUnboundServerSentEventsNotices</code> setting (default <code>true</code>).</p><h3 id="reliable-sse-connection-handshake" tabindex="-1">Reliable SSE connection handshake <a class="header-anchor" href="#reliable-sse-connection-handshake" aria-label="Permalink to &quot;Reliable SSE connection handshake&quot;">​</a></h3><p>SSE responses now flush a small &quot;connected&quot; line as soon as the broadcaster has registered the new subscriber, instead of waiting for the first real event. Browsers and <code>EventSource</code> clients ignore comment-only lines per spec, so no consumer behavior changes — but a client that wants to do &quot;subscribe, then publish, then receive&quot; can now rely on the handshake completing before its publish call. Mostly visible to integration tests; in production it makes connection states more predictable.</p><h3 id="startup-error-when-claim-mapped-parameters-use-a-non-text-type" tabindex="-1">Startup error when claim-mapped parameters use a non-text type <a class="header-anchor" href="#startup-error-when-claim-mapped-parameters-use-a-non-text-type" aria-label="Permalink to &quot;Startup error when claim-mapped parameters use a non-text type&quot;">​</a></h3><p>If <code>Auth.UseUserParameters</code> is on and your <code>ParameterNameClaimsMapping</code> references a procedure parameter whose SQL type isn&#39;t text-compatible — for example <code>_company_id int</code> mapped to a <code>company_id</code> claim — every authenticated request used to crash with this error from deep inside the driver:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>System.InvalidCastException: Writing values of &#39;System.String&#39; is not supported</span></span>
<span class="line"><span>for parameters having NpgsqlDbType &#39;Integer&#39;.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><p>The exception didn&#39;t mention claim mapping, so debugging meant a stack-trace hunt. NpgsqlRest now catches the misdeclaration at startup with a precise message naming the endpoint, parameter, claim, and the SQL type:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Endpoint POST /api/create-local-user parameter _company_id is mapped to claim</span></span>
<span class="line"><span>&#39;company_id&#39; but its type is &#39;int&#39; which is not text-compatible. Claim values</span></span>
<span class="line"><span>are strings, so binding would fail at runtime with InvalidCastException.</span></span>
<span class="line"><span>Declare the parameter as text/varchar/char/json/jsonb/xml/jsonpath, or remove</span></span>
<span class="line"><span>&#39;_company_id&#39; from ParameterNameClaimsMapping.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><p>Accepted types: <code>text</code>, <code>varchar</code>, <code>char</code>, <code>name</code>, <code>xml</code>, <code>json</code>, <code>jsonb</code>, <code>jsonpath</code>, plus <code>unknown</code> (the SQL-file-source case where the driver resolves the type server-side). Any other type fails fast at <code>UseNpgsqlRest</code>. The check only runs for endpoints with <code>UseUserParameters</code> enabled and only for parameters that match a configured claim mapping.</p><h3 id="warning-when-a-request-value-is-overridden-by-claim-auto-bind" tabindex="-1">Warning when a request value is overridden by claim auto-bind <a class="header-anchor" href="#warning-when-a-request-value-is-overridden-by-claim-auto-bind" aria-label="Permalink to &quot;Warning when a request value is overridden by claim auto-bind&quot;">​</a></h3><p>When a parameter is auto-bound from a claim, the claim wins — that&#39;s intentional, especially for security-sensitive procedures where the caller&#39;s identity must override anything the request supplies. But if the request <em>also</em> sent a value for that parameter, the value used to be discarded silently. With certain UI patterns (forms that POST every field) this hid real bugs: in one case <code>update_user_roles(_user_id text, _roles text[])</code> looked like it was updating a target user, but every request modified the caller&#39;s own roles because <code>_user_id</code> was claim-mapped.</p><p>The auto-bind still wins (no behavior change for security), but a collision now emits a warning so the developer can see what happened:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Endpoint /api/update-user-roles parameter _user_id received a body value but</span></span>
<span class="line"><span>is auto-bound from claim &#39;name_identifier&#39;. The supplied value is being ignored.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><p>The warning fires only when the request actually supplied a value, naming the endpoint, parameter, source (<code>body</code> or <code>query</code>), and the claim.</p><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><p>A focused pass on response rendering. No public API or configuration changes.</p><h3 id="lower-allocation-json-conversion-for-arrays-and-composites" tabindex="-1">Lower-allocation JSON conversion for arrays and composites <a class="header-anchor" href="#lower-allocation-json-conversion-for-arrays-and-composites" aria-label="Permalink to &quot;Lower-allocation JSON conversion for arrays and composites&quot;">​</a></h3><p>The four PostgreSQL → JSON conversion routines used to render array, composite, and tuple values now rent their working <code>StringBuilder</code> buffers from the existing pool instead of allocating fresh ones on every call. This affects <code>PgArrayToJsonArray</code>, <code>PgCompositeArrayToJsonArray</code>, <code>PgTupleToJsonObject</code>, and <code>PgUnknownToJsonArray</code> — all of which fire per row × per column on responses that include array or composite types.</p><p>Measured on a focused micro-benchmark (Apple M4 Pro, .NET 10, BenchmarkDotNet ShortRun, three iterations):</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Function</th><th style="text-align:right;">Before alloc</th><th style="text-align:right;">After alloc</th><th style="text-align:right;">Δ</th></tr></thead><tbody><tr><td><code>PgArrayToJsonArray</code> (numeric, 100 elem)</td><td style="text-align:right;">1.91 KB</td><td style="text-align:right;">1.16 KB</td><td style="text-align:right;"><strong>−39%</strong></td></tr><tr><td><code>PgArrayToJsonArray</code> (text, 100 elem)</td><td style="text-align:right;">19.68 KB</td><td style="text-align:right;">13.86 KB</td><td style="text-align:right;"><strong>−29%</strong></td></tr><tr><td><code>PgCompositeArrayToJsonArray</code> (50 elem)</td><td style="text-align:right;">23.02 KB</td><td style="text-align:right;">11.52 KB</td><td style="text-align:right;"><strong>−50%</strong></td></tr><tr><td><code>PgTupleToJsonObject</code> (10 fields)</td><td style="text-align:right;">1.10 KB</td><td style="text-align:right;">1.27 KB</td><td style="text-align:right;">within noise</td></tr></tbody></table></div></div><p>CPU time per call moved by single-digit percent — within or near the noise band of a short BDN run. The headline win is reduced <strong>GC pressure</strong> during sustained load: a 100-row response containing several array columns can drop ~1–2 MB of allocation per request, and a multi-row composite-array response can drop ~5–10 MB.</p><h4 id="estimated-impact-on-the-postgresql-rest-api-benchmark-workloads" tabindex="-1">Estimated impact on the <a href="/blog/benchmarks-2026-07/">PostgreSQL REST API benchmark</a> workloads <a class="header-anchor" href="#estimated-impact-on-the-postgresql-rest-api-benchmark-workloads" aria-label="Permalink to &quot;Estimated impact on the [PostgreSQL REST API benchmark](/blog/benchmarks-2026-07/) workloads&quot;">​</a></h4><p>These are <strong>extrapolations from the micro-benchmark above</strong>, not re-measured numbers from re-running the published benchmark. They estimate how the allocation reduction translates to throughput and tail latency under that benchmark&#39;s 100 VU sustained concurrency — where reduced GC pressure compounds. Scenarios with little or no array/composite work see essentially no change because the optimized paths don&#39;t fire.</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Scenario</th><th style="text-align:right;">Baseline (3.4.7)</th><th>What fires</th><th style="text-align:right;">Est. req/s Δ</th><th style="text-align:right;">Est. P99 latency Δ</th></tr></thead><tbody><tr><td>Minimal Baseline</td><td style="text-align:right;">16,065 req/s</td><td>Nothing — no arrays, no composites</td><td style="text-align:right;"><strong>0%</strong></td><td style="text-align:right;">0%</td></tr><tr><td>Many Parameters (20)</td><td style="text-align:right;">11,504 req/s</td><td>Query-string parsing only — not touched</td><td style="text-align:right;"><strong>0%</strong></td><td style="text-align:right;">0%</td></tr><tr><td>POST Body (10 rec)</td><td style="text-align:right;">6,101 req/s</td><td>Arrays in 10-row response</td><td style="text-align:right;"><strong>+1 to +3%</strong></td><td style="text-align:right;">−2 to −5%</td></tr><tr><td>Data Type (1 rec)</td><td style="text-align:right;">4,588 req/s</td><td>Few array columns × 1 row</td><td style="text-align:right;"><strong>+0 to +2%</strong></td><td style="text-align:right;">−2 to −5%</td></tr><tr><td>Nested JSON (depth 1, 100 rows)</td><td style="text-align:right;">3,061 req/s</td><td>Composite paths fire heavily</td><td style="text-align:right;"><strong>+5 to +10%</strong></td><td style="text-align:right;">−5 to −15%</td></tr><tr><td>Large Payload (100 KB)</td><td style="text-align:right;">1,096 req/s</td><td>Depends on payload shape</td><td style="text-align:right;"><strong>+0 to +3%</strong></td><td style="text-align:right;">varies</td></tr><tr><td>Data Type (100 rec)</td><td style="text-align:right;">377 req/s</td><td>Array cols × 100 rows — ~1–2 MB/req cut</td><td style="text-align:right;"><strong>+3 to +7%</strong></td><td style="text-align:right;">−5 to −12%</td></tr><tr><td>Data Type (500 rec)</td><td style="text-align:right;">82 req/s</td><td>Array cols × 500 rows — ~5–10 MB/req cut</td><td style="text-align:right;"><strong>+5 to +10%</strong></td><td style="text-align:right;">−8 to −15%</td></tr></tbody></table></div></div><p>The largest absolute wins land on the high-record-count scenarios where allocation pressure is greatest. The largest relative tail-latency improvements land on the same scenarios because Gen0 stalls dominate P99 under that load shape.</p><p>Two important caveats:</p><ol><li><strong>The published benchmark measured 3.4.7.</strong> Current <code>master</code> already has months of perf work on top of that. These estimates apply on top of current state; they assume the relative shape (CPU vs. PostgreSQL vs. network) hasn&#39;t shifted dramatically since 3.4.7.</li><li><strong>End-to-end requests spend most of their time in PostgreSQL, network round-trip, and Kestrel.</strong> The optimized paths are a slice of response rendering, so the gains compound only where rendering CPU or GC is the bottleneck. For a single-row response the optimized work is microseconds out of milliseconds; for a 500-row array-heavy response it&#39;s a much larger share.</li></ol><h3 id="utf-8-literals-for-json-markup-constants" tabindex="-1">UTF-8 literals for JSON markup constants <a class="header-anchor" href="#utf-8-literals-for-json-markup-constants" aria-label="Permalink to &quot;UTF-8 literals for JSON markup constants&quot;">​</a></h3><p><code>Consts.Utf8OpenBrace</code>, <code>Utf8CloseBrace</code>, <code>Utf8OpenBracket</code>, <code>Utf8CloseBracket</code>, <code>Utf8Comma</code>, <code>Utf8Colon</code>, and <code>Utf8Null</code> are now <code>static ReadOnlySpan&lt;byte&gt;</code> properties backed by <code>&quot;x&quot;u8</code> UTF-8 string literals, instead of <code>static readonly byte[]</code> fields. The bytes are embedded directly in the assembly metadata, so each access is a pointer-and-length to read-only data — zero heap allocation, ever. Eliminates seven small startup-time allocations.</p><h3 id="tighter-pipewriter-writes" tabindex="-1">Tighter PipeWriter writes <a class="header-anchor" href="#tighter-pipewriter-writes" aria-label="Permalink to &quot;Tighter PipeWriter writes&quot;">​</a></h3><p>The hot-path JSON markup writes (commas, braces, brackets, the <code>&quot;null&quot;</code> literal) have been collapsed from a three-step <code>GetSpan / CopyTo / Advance</code> pattern to a single <code>IBufferWriter&lt;byte&gt;.Write(ReadOnlySpan&lt;byte&gt;)</code> call across ten call sites in the response renderer. Same allocation profile, fewer chances to mismatch sizes.</p><h2 id="hardening-silent-failure-fixes" tabindex="-1">Hardening (silent-failure fixes) <a class="header-anchor" href="#hardening-silent-failure-fixes" aria-label="Permalink to &quot;Hardening (silent-failure fixes)&quot;">​</a></h2><p>Each of these fixes a class of silent failure that used to require log digging or memory monitoring to detect.</p><h3 id="arraypool-rent-now-in-try-finally" tabindex="-1"><code>ArrayPool</code> rent now in <code>try/finally</code> <a class="header-anchor" href="#arraypool-rent-now-in-try-finally" aria-label="Permalink to &quot;\`ArrayPool\` rent now in \`try/finally\`&quot;">​</a></h3><p><code>PgCompositeArrayToJsonArray</code> rents a <code>char[]</code> from <code>ArrayPool&lt;char&gt;.Shared</code> for inputs over 512 chars and previously returned it only on the success path. If the parsing loop threw, the rented buffer was lost from the shared pool until process exit — a slow, silent leak that compounded over uptime. Returns now happen in <code>finally</code>, so a malformed PostgreSQL value can&#39;t poison the pool.</p><h3 id="multi-command-stringbuilder-rentals-always-released" tabindex="-1">Multi-command StringBuilder rentals always released <a class="header-anchor" href="#multi-command-stringbuilder-rentals-always-released" aria-label="Permalink to &quot;Multi-command StringBuilder rentals always released&quot;">​</a></h3><p>The <code>mcRowBuilder</code> and <code>mcCompositeBuffer</code> StringBuilders rented inside the multi-command result-rendering loop are now lifted to method scope and released in an outer <code>finally</code> even if the inner reader loop throws.</p><h3 id="proxy-out-buffer-released-on-exception-path" tabindex="-1"><code>proxy_out</code> buffer released on exception path <a class="header-anchor" href="#proxy-out-buffer-released-on-exception-path" aria-label="Permalink to &quot;\`proxy_out\` buffer released on exception path&quot;">​</a></h3><p>The <code>MemoryStream</code> used by the <code>proxy_out</code> feature to capture function output before forwarding upstream is now disposed in an inner <code>try/finally</code>, so a forwarding failure can&#39;t leak the buffer.</p><h3 id="column-decryption-failures-now-logged-at-trace" tabindex="-1">Column-decryption failures now logged at Trace <a class="header-anchor" href="#column-decryption-failures-now-logged-at-trace" aria-label="Permalink to &quot;Column-decryption failures now logged at Trace&quot;">​</a></h3><p>Three call sites that decrypt column values via <code>IDataProtector.Unprotect</code> previously had silent <code>catch { }</code> blocks — by design, so a failed decryption falls back to the raw ciphertext rather than surfacing as a 500. The fall-back is preserved, but the failure is now logged at <code>LogLevel.Trace</code>:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Column decryption failed; falling back to raw value. Error: &lt;message&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>A misconfigured key, a tampered ciphertext, or a key-rotation mismatch is now observable when Trace logging is enabled instead of being completely silent.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>One new optional setting:</p><ul><li><code>WarnUnboundServerSentEventsNotices</code> (default <code>true</code>) — controls the new &quot;missed <code>@sse_publish</code>&quot; warning described above. Set <code>false</code> if your project intentionally uses <code>RAISE</code> for non-SSE logging and you don&#39;t want NpgsqlRest commenting on it.</li></ul><p>No keys removed or renamed; existing <code>appsettings.json</code> works as-is.</p><h2 id="test-suite" tabindex="-1">Test suite <a class="header-anchor" href="#test-suite" aria-label="Permalink to &quot;Test suite&quot;">​</a></h2><p>1949 tests pass on the release branch. 12 of those are new for the SSE work (URL routing under each annotation combination, end-to-end live event delivery from a publisher procedure to a subscriber on a different procedure&#39;s URL, the missed-annotation warning, TS client output for both new annotations) and 5 are new for the claim auto-bind diagnostics. A new <code>SseTestClient</code> helper opens streaming HTTP connections and waits for the broadcaster to register subscribers before publishing — reusable for upcoming SSE work like heartbeats and <code>Last-Event-ID</code> resume.</p>`,72)]))}const g=t(o,[["render",r]]);export{u as __pageData,g as default};
